// Dashboard.js - Updated with Detailed Analysis Charts
import React, { useState, useEffect } from 'react';
import './Dashboard.css';

function Dashboard({ dashboardData }) {
  const [activeTab, setActiveTab] = useState('overview');
  const [chartData, setChartData] = useState(null);

  // Generate sample chart data when component mounts or data changes
  useEffect(() => {
    if (dashboardData) {
      generateChartData();
    }
  }, [dashboardData]);

  const generateChartData = () => {
    const apiData = dashboardData.individualResult || {};
    
    // Sample data for charts - in real app, this would come from your API
    const data = {
      riskFactors: [
        { feature: 'Days Since Last Order', importance: 0.32, impact: 'high' },
        { feature: 'Satisfaction Score', importance: 0.28, impact: 'high' },
        { feature: 'Cashback Amount', importance: 0.15, impact: 'medium' },
        { feature: 'Tenure Duration', importance: 0.12, impact: 'medium' },
        { feature: 'Order Frequency', importance: 0.08, impact: 'low' },
        { feature: 'Complaint History', importance: 0.05, impact: 'high' }
      ],
      trendAnalysis: [
        { month: 'Jan', churnRisk: 25, satisfaction: 4.2, orders: 8 },
        { month: 'Feb', churnRisk: 32, satisfaction: 3.8, orders: 6 },
        { month: 'Mar', churnRisk: 45, satisfaction: 3.5, orders: 5 },
        { month: 'Apr', churnRisk: 62, satisfaction: 3.2, orders: 4 },
        { month: 'May', churnRisk: 79, satisfaction: 2.8, orders: 3 }
      ],
      comparisonMetrics: {
        current: {
          churnRisk: 79,
          satisfaction: 2.8,
          orderFrequency: 23,
          cashbackUtilization: 45
        },
        benchmark: {
          churnRisk: 15,
          satisfaction: 4.5,
          orderFrequency: 7,
          cashbackUtilization: 78
        }
      }
    };
    
    setChartData(data);
  };

  if (!dashboardData) {
    return (
      <div className="dashboard">
        <div className="dashboard-header">
          <h2>Churn Analysis Dashboard</h2>
        </div>
        <div className="dashboard-placeholder">
          <div className="placeholder-content">
            <span className="placeholder-icon">🔍</span>
            <h3>No Analysis Data Available</h3>
            <p>Run a customer analysis to view insights and predictions</p>
          </div>
        </div>
      </div>
    );
  }

  // Extract data from API response
  const apiData = dashboardData.individualResult || {};
  
  // Enhanced data with dynamic values from API
  const analysisData = {
    churnRisk: Math.round((apiData.probability || 0.792) * 1000) / 10,
    retentionProbability: Math.round((1 - (apiData.probability || 0.792)) * 1000) / 10,
    riskLevel: apiData.risk_level || "high",
    confidence: 92,
    trend: "increasing",
    lastMonthComparison: 5.7,
    
    executiveSummary: {
      riskProbability: Math.round((apiData.probability || 0.792) * 1000) / 10,
      category: apiData.risk_level === "high" ? "critical" : apiData.risk_level === "medium" ? "monitoring" : "stable",
      riskLevel: apiData.risk_level === "high" ? "high immediate risk" : apiData.risk_level === "medium" ? "moderate risk" : "low immediate risk",
      recommendation: apiData.risk_level === "high" ? "immediate intervention required" : 
                     apiData.risk_level === "medium" ? "proactive monitoring recommended" : 
                     "proceeding directly to the action plan below",
      primaryRiskFactor: apiData.top_driver || "general behavior"
    },
    
    comparisonMetrics: {
      churnRisk: { 
        current: `${Math.round((apiData.probability || 0.792) * 1000) / 10}%`, 
        target: "<15%", 
        comparison: apiData.probability > 0.15 ? "Above Target" : "Below Target",
        value: Math.round((apiData.probability || 0.792) * 1000) / 10
      },
      tenure: { 
        current: `${apiData.customer_data?.Tenure || 3} mo`, 
        target: ">12 mo", 
        comparison: (apiData.customer_data?.Tenure || 3) > 12 ? "Above Target" : "Below Target",
        value: apiData.customer_data?.Tenure || 3
      },
      daysSinceOrder: { 
        current: `${apiData.customer_data?.DaySinceLastOrder || 25} d`, 
        target: "<7 d", 
        comparison: (apiData.customer_data?.DaySinceLastOrder || 25) > 7 ? "Above Target" : "Below Target",
        value: apiData.customer_data?.DaySinceLastOrder || 25
      },
      satisfaction: { 
        current: `${apiData.customer_data?.SatisfactionScore || 2}/5`, 
        target: ">4/5", 
        comparison: (apiData.customer_data?.SatisfactionScore || 2) > 4 ? "Above Target" : "Below Target",
        value: apiData.customer_data?.SatisfactionScore || 2
      }
    },
    
    businessImpact: apiData.business_impact ? {
      estimatedCV: `₹${Math.round(apiData.business_impact.estimated_clv || 18750).toLocaleString()}`,
      retentionBudget: `₹${Math.round(apiData.business_impact.retention_budget || 1250).toLocaleString()}`,
      potentialLoss: `₹${Math.round(apiData.business_impact.potential_revenue_loss || 4250).toLocaleString()}`,
      roiPotential: `${Math.round((apiData.business_impact.roi_retention || 3.4) * 10) / 10}x`
    } : {
      estimatedCV: "₹18,750",
      retentionBudget: "₹1,250",
      potentialLoss: "₹4,250",
      roiPotential: "3.4x"
    }
  };

  // Churn Risk Factors Chart Component
  const RiskFactorsChart = () => {
    if (!chartData) return null;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Key Churn Risk Factors</h3>
          <span className="chart-subtitle">Feature Importance Analysis</span>
        </div>
        <div className="chart-content">
          <div className="risk-factors-list">
            {chartData.riskFactors.map((factor, index) => (
              <div key={index} className="risk-factor-item">
                <div className="factor-header">
                  <span className="factor-name">{factor.feature}</span>
                  <span className="factor-importance">{Math.round(factor.importance * 100)}%</span>
                </div>
                <div className="factor-bar-container">
                  <div 
                    className={`factor-bar ${factor.impact}`}
                    style={{ width: `${factor.importance * 100}%` }}
                  ></div>
                </div>
                <div className="factor-impact">
                  <span className={`impact-badge ${factor.impact}`}>
                    {factor.impact.toUpperCase()} IMPACT
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  // Trend Analysis Chart Component
  const TrendAnalysisChart = () => {
    if (!chartData) return null;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Customer Behavior Trends</h3>
          <span className="chart-subtitle">Last 5 Months Analysis</span>
        </div>
        <div className="chart-content">
          <div className="trend-chart">
            <div className="chart-legend">
              <div className="legend-item">
                <div className="legend-color churn-risk"></div>
                <span>Churn Risk %</span>
              </div>
              <div className="legend-item">
                <div className="legend-color satisfaction"></div>
                <span>Satisfaction Score</span>
              </div>
              <div className="legend-item">
                <div className="legend-color orders"></div>
                <span>Monthly Orders</span>
              </div>
            </div>
            
            <div className="trend-bars">
              {chartData.trendAnalysis.map((monthData, index) => (
                <div key={index} className="trend-bar-group">
                  <div className="bar-labels">
                    <span className="month-label">{monthData.month}</span>
                    <span className="risk-value">{monthData.churnRisk}%</span>
                  </div>
                  
                  <div className="bars-container">
                    {/* Churn Risk Bar */}
                    <div className="bar-wrapper">
                      <div 
                        className="bar churn-risk"
                        style={{ height: `${monthData.churnRisk}%` }}
                        title={`Churn Risk: ${monthData.churnRisk}%`}
                      ></div>
                    </div>
                    
                    {/* Satisfaction Bar */}
                    <div className="bar-wrapper">
                      <div 
                        className="bar satisfaction"
                        style={{ height: `${monthData.satisfaction * 20}%` }}
                        title={`Satisfaction: ${monthData.satisfaction}/5`}
                      ></div>
                    </div>
                    
                    {/* Orders Bar */}
                    <div className="bar-wrapper">
                      <div 
                        className="bar orders"
                        style={{ height: `${monthData.orders * 10}%` }}
                        title={`Orders: ${monthData.orders}`}
                      ></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  };

  // Performance Comparison Chart
  const PerformanceComparisonChart = () => {
    if (!chartData) return null;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Performance vs Benchmark</h3>
          <span className="chart-subtitle">Current vs Target Metrics</span>
        </div>
        <div className="chart-content">
          <div className="comparison-chart">
            {Object.entries(chartData.comparisonMetrics.current).map(([metric, value], index) => {
              const benchmark = chartData.comparisonMetrics.benchmark[metric];
              const metricsConfig = {
                churnRisk: { label: 'Churn Risk', format: '%', reverse: true },
                satisfaction: { label: 'Satisfaction', format: '/5', reverse: false },
                orderFrequency: { label: 'Days Between Orders', format: ' days', reverse: true },
                cashbackUtilization: { label: 'Cashback Used', format: '%', reverse: false }
              };
              
              const config = metricsConfig[metric];
              const isPositive = config.reverse ? value < benchmark : value > benchmark;
              
              return (
                <div key={metric} className="comparison-item">
                  <div className="comparison-label">{config.label}</div>
                  <div className="comparison-bars">
                    <div className="value-bar current">
                      <div 
                        className={`bar-fill ${isPositive ? 'positive' : 'negative'}`}
                        style={{ width: `${Math.min((value / 100) * 100, 100)}%` }}
                      ></div>
                      <span className="bar-value">
                        {value}{config.format}
                      </span>
                    </div>
                    <div className="value-bar benchmark">
                      <div 
                        className="bar-fill benchmark"
                        style={{ width: `${Math.min((benchmark / 100) * 100, 100)}%` }}
                      ></div>
                      <span className="bar-value">
                        {benchmark}{config.format}
                      </span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    );
  };

  // Customer Retention Action Plan
  const RetentionActionPlan = () => (
    <div className="chart-card">
      <div className="chart-header">
        <h3>Customer Retention Action Plan</h3>
        <span className="chart-subtitle">Priority Actions for Risk Mitigation</span>
      </div>
      <div className="chart-content">
        <div className="action-plan">
          <div className="action-category immediate">
            <h4>🚨 Immediate Actions (Next 24-48 hours)</h4>
            <ul>
              <li>Personalized outreach from dedicated account manager</li>
              <li>Exclusive limited-time discount offer (25% off next purchase)</li>
              <li>Priority customer service hotline access</li>
            </ul>
          </div>
          
          <div className="action-category short-term">
            <h4>📅 Short-term Actions (Next 7 days)</h4>
            <ul>
              <li>Personalized product recommendations based on browsing history</li>
              <li>Loyalty program tier upgrade with enhanced benefits</li>
              <li>Customer satisfaction survey with incentive completion</li>
            </ul>
          </div>
          
          <div className="action-category long-term">
            <h4>🎯 Long-term Strategy (Next 30 days)</h4>
            <ul>
              <li>Regular personalized communication cadence</li>
              <li>Early access to new products and promotions</li>
              <li>Quarterly business review and value assessment</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );

  // Enhanced Overview Tab
  const renderOverview = () => (
    <div className="overview-tab-enhanced">
      {/* Your existing overview components */}
      <div className="overview-content">
        {/* Include your existing overview components here */}
        <p>Overview content goes here...</p>
      </div>
    </div>
  );

  // Detailed Analysis Tab with Charts
  const renderDetailedAnalysis = () => (
    <div className="detailed-analysis-tab">
      <div className="analysis-grid">
        <div className="analysis-column">
          <RiskFactorsChart />
          <PerformanceComparisonChart />
        </div>
        <div className="analysis-column">
          <TrendAnalysisChart />
          <RetentionActionPlan />
        </div>
      </div>
    </div>
  );

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <div className="header-main">
          <h2>Churn Analysis Dashboard</h2>
        </div>
        <div className="header-actions">
          <button className="btn secondary">Export Report</button>
          <button className="btn primary">Save Analysis</button>
        </div>
      </div>

      <div className="dashboard-nav">
        <div className="nav-tabs">
          <button className={`nav-button ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => setActiveTab('overview')}>
            Overview
          </button>
          <button className={`nav-button ${activeTab === 'detailed' ? 'active' : ''}`}
            onClick={() => setActiveTab('detailed')}>
            Detailed Analysis
          </button>
        </div>
      </div>

      <div className="tab-content">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'detailed' && renderDetailedAnalysis()}
      </div>
    </div>
  );
}

export default Dashboard;
